var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"흐아아……. 개운하다…….","JPN":"ふああ……すっきり……","ENG":"Ahh... I feel so refreshed...","TWN":"呼哈～～真舒服……"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜만에 푹 잤어! 꿈을… 악몽을…… 안 꾼 것 같아.","JPN":"久しぶりにぐっすり寝たよ！　夢を……悪夢を……見てないみたい。","ENG":"I haven’t slept like this in ages! And I... don’t think I had any nightmares too.","TWN":"好久沒睡得這麼沉了！好像…完全……沒有做惡夢。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"어? 나도! 공기도 상쾌한 게…… 벽이 뚫려서 그런 줄 알았는데 악몽을 안 꿨네.","JPN":"え？　私も！　空気もさわやかで……壁に穴があいたからかと思ったんだけど、悪夢を見てないや。","ENG":"Huh? Me too! Even the air feels fresh... I thought it was because of the hole in the wall, but it’s because I didn’t have a nightmare.","TWN":"這麼說來？我也是欸！空氣好清新……我還以為是因為牆被踹破的關係，原來是因為沒做惡夢！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"벼, 벽은 왜 저래?! 진짜 구멍이 뚫렸잖아?","JPN":"か、壁はどうなってるの！？　本当に穴があいてるじゃん！","ENG":"W-what happened to the wall?! There’s really a hole in it!!","TWN":"牆…牆壁怎麼變那樣？！真的破了個大洞欸？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RUNAWAY_NPC_OZ_NAME","text":{"KOREA":"너희는…… 도로시?","JPN":"あんたたちは……ドロシー？","ENG":"Hey, aren’t you... Dorothy?","TWN":"你們是……桃樂絲？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"지나! 정신이 좀 들어?","JPN":"ジナ！　気がついた？","ENG":"Gina! Do you finally recognize me?","TWN":"吉娜！你恢復了嗎？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RUNAWAY_NPC_OZ_NAME","text":{"KOREA":"도로시! 여긴 왜 또 돌아온 거야! 미쳤어?!","JPN":"ドロシー！　なんで戻ってきたの！　頭おかしくなった！？","ENG":"Dorothy! Why did you come back here? Are you crazy?!","TWN":"桃樂絲！你為什麼又回來這裡！你腦袋壞掉嗎？！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"안 미쳤어! 돌아온 게 아니라 구하러 온 거야.","JPN":"おかしくなってないよ！　戻ったんじゃなくて、助けに来たんだ。","ENG":"Nope! I didn’t just come back. I’m here to rescue you.","TWN":"才沒壞！我是回來救你們的！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RUNAWAY_NPC_OZ_NAME","text":{"KOREA":"우릴…… 구하러?","JPN":"私たちを……助けに？","ENG":"Rescue... us?","TWN":"回來……救我們？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"응. 네 덕분에 우리가 도망갔었으니까, 이젠 우리가 너흴 도와줄 차례지.","JPN":"うん。君のおかげで逃げられたから、今度は私たちがジナたちを助ける番だ。","ENG":"Yeap. We were able to escape because of you. So now it’s our turn to help you.","TWN":"嗯，因為你我們才能逃離這裡，所以現在換我們回來救你們！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"관리국 정보원이랑 연락해서 보호받았어. 덕분에 너희를 구하러 올 정보도 공유 받았고.","JPN":"管理局の情報員に連絡を取って、保護してもらったんだ。おかげで君たちを助けにくるための情報ももらえたし。","ENG":"We got in contact with an informant from the Administration. Thanks to her, we were able to get intel about your whereabouts.","TWN":"我們和管理局的情報員聯絡上後，受到庇護。她還跟我們分享很多情報，讓我們可以來救你們。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RUNAWAY_NPC_OZ_NAME","text":{"KOREA":"……넣어둔 핸드폰이 도움이 됐나 보네. 다행이다.","JPN":"……入れておいた携帯、役に立ったんだね。よかった。","ENG":"I guess that smartphone helped you out. Thank goodness.","TWN":"……太好了，看來我放在你口袋裡的手機有發揮作用。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"……가루의 힘이 대단하네. 마치 처음 본 사람처럼 굴고 있어.","JPN":"……粉の力、すごいじゃん。まるで今初めて会った人みたいになってる。","ENG":"That powder is really something. They’re acting like they’re seeing us for the first time.","TWN":"……粉末的效果還真厲害，可以把人變得像陌生人一樣。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"기억이 나도 환상이었다고 생각할 거야. 저 애들은 이제야 현실로 돌아온 셈이지.","JPN":"思い出しても幻だったと思うはずだよ。あの子たちはやっと現実に戻ったんだ。","ENG":"Even if they did remember, they would have dismissed it as a hallucination. For them, they’ve just returned to reality.","TWN":"就算有記憶也會以為是幻想吧，他們現在才是真的回到現實。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"도로시. 회포를 푸는 건 좋은데 시간이 많이 흘렀어. 얼른 가야 돼.","JPN":"ドロシーちゃん。積もる話があるのはわかるけど、結構時間が経ったよ。早く行かなきゃ。","ENG":"Dorothy. I know you want to catch up with your friend, but now is not the time. We have to go.","TWN":"桃樂絲，現在時間不多，必須趕快離開，等出去後再敘舊吧。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"아참. 그래! 얘들아, 우리랑 같이…… 갈 거지?","JPN":"あっ、そうだよな！　みんな、一緒に……行くよな？","ENG":"Oh, right. Okay! Guys? You’re coming with us... right?","TWN":"對吼！你說的沒錯！大家，和我們一起……走吧？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":null,"text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"아직도 여기에 머물 생각이라면…….","JPN":"まさかここに残る気じゃ……","ENG":"You’re still not thinking of...","TWN":"你們該不會還想繼續待在這……"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"RUNAWAY_NPC_OZ_NAME","text":{"KOREA":"뭣들 해? 빨리 짐 싸!","JPN":"何してるの？　早く荷造りして！","ENG":"What are you all doing? Go pack your bags!","TWN":"你們在想什麼？還不快打包行李！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"RUNAWAY_NPC_OZ_NAME","text":{"KOREA":"아니다, 쌀 짐도 없구나. 빨리들 일어나!! 도망갈 절호의 기회라고!","JPN":"ううん、荷造りをするものもないよ。早く立って！！　逃げるチャンスなんだから！","ENG":"No, there’s nothing to pack. Get up!! This is our chance to get out of here for good!","TWN":"不對，哪有什麼行李好打包，大家快起來！！現在是可以逃離這裡的大好機會！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":null,"text":{"KOREA":"지, 진짜야? 우리 진짜 나갈 수 있어?","JPN":"ほ、本当？　本当に出られるの？","ENG":"R-really? We can leave?","TWN":"真…真的嗎？我們真的可以離開嗎？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"당연하지. 저쪽 벽이 왜 뚫려 있겠어. 다 나가기 편하라고 도로시가 힘쓴 거지.","JPN":"当たり前だよ。あの穴、なんであいてると思う？　簡単に出られるように、ドロシーが頑張ったんだ。","ENG":"Of course! Why do you think there’s a hole in the wall? Dorothy made it so we can get out easily.","TWN":"當然，那邊牆壁為何會破洞，就是要方便大家逃跑，桃樂絲才努力踹破的。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"어…… 수습해 줘서 고마워?","JPN":"えーっと……フォローありがとう。","ENG":"Uh... Thanks for covering for me.","TWN":"謝謝喔……還幫我找台階下。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"고마우면 초코 막대 과자 한 박스.","JPN":"ありがたく思ってるなら、チョコスティック1箱。","ENG":"As payment, I want a box of chocolate covered cracker sticks.","TWN":"要謝我的話，就來一盒巧克力餅乾棒吧。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"자자. 주목.","JPN":"さて、注目。","ENG":"All right. Attention everyone.","TWN":"大家注意，"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_FINGER_FLICK"},{"id":"L37_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"다들 이 뚫린 벽을 통과하자마자 앞으로 쭉 달려가.","JPN":"みんな、この穴を通ったらそのまま、まっすぐ前に走るんだ。","ENG":"As soon as you go through that hole in the wall, run straight forward.","TWN":"大家一通過牆上的洞後，就一直往前跑。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"폐 놀이공원도 지나고, 골목길도 지날 텐데 일단 쭉 가.","JPN":"廃遊園地を通って、路地も通るだろうけど、とにかくまっすぐ行くこと。","ENG":"Go past the abandoned theme park and alleyway.","TWN":"你們會先路過廢棄的遊樂園，再路過巷子，總之就是一直跑。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"그러면 길 한복판에 빨간 머리 메이드 언니가 있을 거거든?","JPN":"そうしたら、道の真ん中に赤髪のメイドのお姉さんがいるはずだ。","ENG":"Continue running until you see a red-haired maid standing in the middle of the street, okay?","TWN":"接著就會在路中央，看到一位紅髮女僕姊姊。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"RUNAWAY_NPC_OZ_NAME","text":{"KOREA":"메이드라고? 메이드?","JPN":"メイド？　えっ、メイド？","ENG":"A maid? Did you just say maid?","TWN":"你說女僕？認真？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"수상하다고 지나치지 말고 그 언니를 따라가. 우릴 도와주실 분이시니까.","JPN":"怪しいからって通り過ぎないで、そのお姉さんについて行くこと。私たちを助けてくれる方だからね。","ENG":"She’s not someone suspicious, so follow her. She’s going to help us.","TWN":"千萬不要覺得奇怪就不理她，要跟著她走，她會幫助我們。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"<color=#ffd34c>레드 리코리스</color>? 어떻게 알고?!","JPN":"<color=#ffd34c>レッドリコリス</color>？　どうやって！？","ENG":"<color=#ffd34c>Red Lycoris</color>? But how?!","TWN":"<color=#ffd34c>紅髮莉克麗絲</color>？她是怎麼知道的？！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"그러게. 우리 몰래 나온 거 아니었어?","JPN":"そうだよ。私たち、こっそり出てきたんじゃなかったの？","ENG":"Yeah. Didn’t we sneak out though?","TWN":"對啊，我們不是瞞著她跑出來的嗎？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"지원 요청은 벌써 해뒀어. 도로시 따라 무작정 올 때부터 별 대책이 없을 것 같더라고.","JPN":"とっくに支援要請を出しておいたよ。ドロシーについてきた時から、特に対策がなさそうだったから。","ENG":"I already requested reinforcements. I had a feeling there wasn’t going to be any plan when we followed Dorothy here.","TWN":"是我請她幫忙的，打從跟著桃樂絲沒頭沒腦地跑出來時，就想說好像沒什麼計畫可言。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"바로 이게 내가 수아를 데려온 이유지! 잘했어! 막대 과자 다섯 박스 사 줄게!","JPN":"これこそ私がコトリを連れてきた理由だよ！　よくやった！　チョコスティック5箱買ってやる！","ENG":"That’s exactly why I brought you, Skia! Good job! I’ll buy you 5 boxes of cracker sticks!","TWN":"這就是我為什麼要帶上你的原因啦！做得很好！我買五盒巧克力餅乾棒給你！！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"받고 하나 더.","JPN":"もう1箱追加で。","ENG":"I’ll take that, and another one.","TWN":"我接受，再多一盒。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"아하하. 나도 하나 선물할 거 있어.","JPN":"あはは。私もプレゼントあるよ。","ENG":"Ahaha. I also have something.","TWN":"哈哈哈，我也有禮物。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"……그 흉악하게 생긴 건 뭐야?","JPN":"……その凶悪なものは何？","ENG":"What’s that hideous thing?","TWN":"……那個長得很可怕的東西是什麼？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"빨간 불빛이 반짝거리는 게 꼭…….","JPN":"赤い光がピカピカしてるのが、まるで……","ENG":"It keeps blinking red like a...","TWN":"閃爍的紅色火光就像是……"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"폭탄. 엄청 센 폭탄이라고 하던데?","JPN":"爆弾。威力がすごいみたいだよ？","ENG":"Bomb. I heard it was a really strong one too.","TWN":"炸彈，好像說是很威的炸彈？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"여길 왔다 갔다 하는 동안 곳곳에 떨어트려 놨어.","JPN":"ここを行き来してる間に、あっちこっちに置いておいたんだ。","ENG":"While we were running about, I placed some of them here and there.","TWN":"我們進出的時候，我有在四處埋下炸彈。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"뭐…… 뭐?! 다 죽일 셈이야?!","JPN":"は……はあ！？　全部殺す気！？","ENG":"Uh... What?! Are you trying to get us killed?!","TWN":"什……什麼？你是想殺光我們嗎？！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"그럴 리가 없잖아.","JPN":"まさか。","ENG":"Of course not.","TWN":"當然不可能囉。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"여길…… 모조리 폭파시킬 거야.","JPN":"ここを……全部爆発させるの。","ENG":"I’m... going to blow this place up.","TWN":"我是要把這裡……整個炸掉。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"뭐?!","JPN":"なっ！？","ENG":"WHAT?!","TWN":"什麼？！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"이건 계획에 없었는데.","JPN":"これは計画外だな。","ENG":"That wasn’t part of the plan.","TWN":"這不在計畫裡吧。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"장소가 남아 있으면 언제든 다시 모이기 쉽거든.","JPN":"場所が残ってると、いつでも簡単にまた集まれちゃうから。","ENG":"If this place remains, they can regather easily.","TWN":"只要據點還在，還是可能會有其他孩子被拐來。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"언더그라운드에서도 상대 조직을 궤멸시킬 때 제일 먼저 하는 게 바로 진영 파괴라고.","JPN":"アンダーグラウンドでも相手の組織を壊滅させる時に一番最初にやるのが陣営を破壊することなんだ。","ENG":"Even in the Underground, the first thing to do when exterminating the enemy organization is to blow up their base.","TWN":"在地下世界裡，要擊垮對手的組織時，也都是先從破壞對手的據點開始。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"폭발 반경은?","JPN":"爆発の半径は？","ENG":"What is the radius of the blast?","TWN":"那爆炸的半徑是？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"이 시설 전체가 날아갈 정도는 될 거야.","JPN":"この施設全体がぶっ飛んじゃうくらいにはなるはずだよ。","ENG":"It’s enough to completely obliterate this whole facility.","TWN":"應該整棟樓都會被炸飛。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"어디서 훔쳤어?","JPN":"どこから盗んだんだ？","ENG":"Where did you steal it from?","TWN":"炸彈是從哪偷來的？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"……관리국 정보부 무기 창고.","JPN":"……管理局情報部の武器庫。","ENG":"...The Administration Intelligence Agency’s weapon storage.","TWN":"……管理局情報部的武器倉庫。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"아직 나도 못 뚫어낸 곳을 용케도 뚫었네.","JPN":"まだワタシも侵入できてないのに、よく突破したね。","ENG":"I haven’t even been able to get through that place. How did you do it?","TWN":"那個地方連我都進不去，你竟然可以闖進去。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"토토랑 친해진 정보부 아저씨가 들어갈 때 잠깐 따라 들어갔어.","JPN":"トトと仲良くなった情報部のおじさんが入る時に、ちょっとだけ一緒に入ったの。","ENG":"I followed Mr. Intelligence agent inside, whom Toto had become acquainted.","TWN":"我趁一個和托托很好的情報部大叔進去時，跟著一起進去的。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"주머니에는 안 들어가서 토토 입 속에 잔뜩 숨겨서 나왔는데도 모르더라.","JPN":"ポケットに入らないからトトの口の中にいっぱい入れて来たんだけど、気付いてないみたいだったよ。","ENG":"They didn't fit in my pocket, so I stuffed a bunch of them inside Toto's mouth, and he didn't notice.","TWN":"因為量太多口袋裝不下，我就藏在托托的嘴裡，所以出來的時候他也沒發現。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"어떤 아저씨일지 왠지 알 것 같네.","JPN":"誰かわかる気がする。","ENG":"I think I know the person you’re talking about.","TWN":"總覺得好像知道那位大叔是誰。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"나도. 턱수염 난 아저씨지?","JPN":"私も。あごひげのおじさんだろ？","ENG":"Me too. It’s Mr. Goatee, isn’t it?","TWN":"我也是，是山羊鬍大叔吧？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"그건 비밀로 할게. 그 분도 난감하실 텐데 존중해드려야지.","JPN":"それは内緒。あの人も困るだろうから、尊重してあげないと。","ENG":"That one I'll keep to myself. We don’t wanna put him in a bad spot.","TWN":"這是秘密，我必須顧一下大叔的面子。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"이제 위저드는 없어.","JPN":"もうウィザードはないんだよ。","ENG":"Now, Wizard is no more.","TWN":"以後就不會再有魔法師，"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"악몽 같은 기억은 떠올리지 말고, 앞으로 편히 자. 얘들아.","JPN":"悪夢のような記憶は忘れて、これからはぐっすり寝てね。みんな。","ENG":"Forget all of your nightmares about this place, and sleep in peace.","TWN":"不要再想起惡夢般的回憶，大家以後就安心睡覺吧。"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"루루. 같이 가자.","JPN":"ルル。一緒に行こう。","ENG":"Lulu, let’s go.","TWN":"露露，我們走吧！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"나도?","JPN":"私も？","ENG":"Me too?","TWN":"我也一起嗎？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"그럼 여기 남아서 한 줌 재가 되려고?","JPN":"じゃあ、ここに残って一握りの灰にでもなるつもり？","ENG":"Are you going to stay here and turn to ash?","TWN":"難道你想留在這裡化成灰嗎？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"그건 아니지만…….","JPN":"それは違うけど……","ENG":"No, but...","TWN":"我不是這個意思……"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"비련의 여주인공 같은 거 나도 많이 꿈꿔 봤는데, 지나가는 행인 1이어도 살아 있는 게 중요한 것 같더라.","JPN":"私も悲劇のヒロインみたいなのによく憧れたけど、たとえエキストラでも生きてるってのが大事だと思うんだ。","ENG":"I've also fantasized about being the tragic heroine, but I quickly realized that it's better to be alive as \\"background actor #1\\" than a dead heroine.","TWN":"雖然我也夢想過要當悲情的女主角，但後來想想，當個路人甲也不錯。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"그래야 친구도 사귀고 맛있는 것도 먹고 기분 좋은 꿈도 꾸지.","JPN":"生きてれば友達も作れるし、美味しいもん食べていい夢も見られる。","ENG":"We need to be alive in order to make new friends, eat delicious food, and dream.","TWN":"不僅可以交朋友，還可以吃好吃的，也不會做惡夢。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"맞아. 하지만 난 가야 돼…….","JPN":"そうだね。でも私は行かなきゃ……","ENG":"Yes. But I have to go...","TWN":"是沒錯，可是我要去……"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L36_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"아. 알아. 네가 이제 뭘 하러 간다는 건지 다 알고 그걸 막을 생각도 없으니까.","JPN":"あ、わかってるって。もうアンタが何しに行くのかも全部知ってるし、それを止める気もないよ。でも。","ENG":"Oh, I know. I now understand what you mean by that and have no intention of stopping you.","TWN":"我知道，我知道你要去做什麼，我也不打算阻止你。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L37_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"잠깐만 쉬다 가라고.","JPN":"ちょっとだけ休んで行きなよ。","ENG":"But all I’m saying is that you could use a rest.","TWN":"但你就休息一下再走吧！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L38_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"잠깐이면 돼.","JPN":"ちょっとでいい。","ENG":"Even if it’s just for a while.","TWN":"休息一下就好。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L39_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"숨 좀 돌리고, 밤하늘도 좀 쳐다보고.","JPN":"息抜きして、ちょっと夜空も見上げて。","ENG":"We could sit back, gaze at the night sky.","TWN":"稍微喘口氣，欣賞一下夜空。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L40_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"아참. 오늘 달은 안 떴대. 떴다가 사라진 거라는데 뭐 아무튼.","JPN":"あ、そうだ。今日は月が出なかったんだって。出て消えたらしいけど、それはいいとして。","ENG":"Oh, the moon’s not out today. Or it suddenly disappeared from what I heard, anyway.","TWN":"對吼，他們說今天沒有月亮，好像原本有，後來又消失的樣子。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L41_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"대신…… 별이 많이 떴어. 달이 없어도 밤하늘을 꽉 채울 만큼.","JPN":"代わりに……星がたくさん見えるんだ。月がなくても夜空をいっぱいにするほど。","ENG":"But... there’re a lot of stars up there. Enough to fill the night sky even without the moon.","TWN":"不過……還有很多星星啦，就算沒有月亮，也有很多星星可以看。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L42_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"나랑 같이 갈 거지?","JPN":"私と一緒に行くよね？","ENG":"So, you’re gonna come with me, right?","TWN":"你會和我一起走吧？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L43_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"자, 손.","JPN":"はい、お手。","ENG":"Gimme your hand.","TWN":"手給我。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L44_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"……후후.","JPN":"……ふふ。","ENG":"Hu hu...","TWN":"……呵呵。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L45_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"그래. 손.","JPN":"そうだね。お手。","ENG":"Okay, here.","TWN":"好，手給你。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L46_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"봐 봐, 말 들으니까 얼마나 좋아?","JPN":"ほら、言うこと聞くといい感じじゃん。","ENG":"See? That wasn’t so hard listening to me, right?","TWN":"你看，這樣聽話多好。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L1_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"와, 저건 다 뭐야? 쉭쉭 날아가는데?","JPN":"うわぁ、何あれ？　ビュンビュン飛んでるよ。","ENG":"Wow... What’s that? Things are zipping across the sky.","TWN":"哇，你們看，好震撼的畫面。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"시설에 보관하고 있던 화약 아닐까?","JPN":"施設で保管していた火薬じゃないかな。","ENG":"Could it be gunpowder they stored in there?","TWN":"是不是原本就存放在裡面的火藥？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"정말? 왠지 불꽃놀이 같네…….","JPN":"本当？　なんだか花火みたいだね……","ENG":"Really? It looks like fireworks...","TWN":"真的嗎？難怪像在放煙火一樣……"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"흥. 지긋지긋한 곳이었는데 그래도 마지막은 예쁘게 터지네.","JPN":"ふん。嫌いな場所だったけど、最後はキレイに散るんだな。","ENG":"Hmph. At least this horrendous place gets to have a pretty ending.","TWN":"哼，原本這麼可怕的地方，沒想到最後這樣還蠻美的。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"……그러게. 진짜 예뻐.","JPN":"……本当。とてもキレイ。","ENG":"Yeah... It is pretty.","TWN":"……沒錯，真的很美。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"아쉬워하지 않아도 돼.","JPN":"残念がらなくていいよ。","ENG":"You don’t need to be sad.","TWN":"不用感到可惜。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"응?","JPN":"ん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"꿈 속에서 언제든 다시 볼 수 있을 거야. 글린다는 잊지 않을 테니까.","JPN":"夢の中でいつでもまた見れる。グリンダは忘れないはずだから。","ENG":"We’ll be able to see each other in our dreams any time you want. Because I won’t forget about you, Glinda.","TWN":"在夢裡隨時都可以再相見，我不會忘記格琳達的。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"……그래. 그러면 좋겠어.","JPN":"……そうだね。そうだといいなぁ。","ENG":"Okay... That sounds nice.","TWN":"……好，那就好。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};